const d = $input.first().json.body;

const esc = (v) => String(v ?? '').replaceAll('&','&amp;').replaceAll('<','&lt;').replaceAll('>','&gt;').replaceAll('"','&quot;').replaceAll("'",'&#39;');
const br  = (v) => esc(v).replace(/\n/g,'<br/>');
const euro = (v) => new Intl.NumberFormat('nl-NL',{style:'currency',currency:'EUR'}).format(Number(v??0));
const dateFmt = (d) => new Intl.DateTimeFormat('nl-NL',{dateStyle:'long'}).format(d);

const vandaag   = new Date();
const geldigTot = new Date(vandaag); geldigTot.setDate(geldigTot.getDate() + 30);

const fromName  = esc(d.from?.companyName ?? '');
const fromEmail = esc(d.from?.email ?? '');
const fromWeb   = esc(d.from?.websiteUrl ?? '');
const fromAddr  = br(d.from?.address ?? '');
const fromVat   = esc(d.from?.vatNumber ?? '');
const fromKvk   = esc(d.from?.kvkNumber ?? '');
const fromPhone = esc(d.from?.phone ?? '');

const offerteNr = esc(d.offerteNumber ?? ('OFF-' + vandaag.getFullYear() + '-' + String(d.proposalId ?? '').slice(-6).toUpperCase()));
const exclBtw   = d.amount != null ? Number(d.amount) : null;
const vatPct    = Number(d.vatRate ?? 21);
const btwBedrag = exclBtw != null ? exclBtw * (vatPct / 100) : null;
const inclBtw   = exclBtw != null ? exclBtw + btwBedrag : null;

const scopeItems = d.scope
  ? String(d.scope).split('\n').map(l => l.trim()).filter(Boolean).map(l => `<li>${esc(l)}</li>`).join('')
  : '';

const html = `<!DOCTYPE html>
<html lang="nl">
<head>
<meta charset="UTF-8"/>
<style>
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
body { font-family: 'Helvetica Neue', Arial, sans-serif; font-size: 12.5px; line-height: 1.65; color: #111827; background: #fff; padding: 48px 52px; }

/* ── Header ── */
.header { display: flex; justify-content: space-between; align-items: flex-start; padding-bottom: 24px; border-bottom: 3px solid #111827; margin-bottom: 32px; }
.brand { font-size: 22px; font-weight: 800; color: #111827; letter-spacing: -.4px; }
.brand-sub { font-size: 11px; color: #6b7280; margin-top: 3px; }
.doc-block { text-align: right; }
.doc-block h1 { font-size: 26px; font-weight: 800; color: #111827; letter-spacing: -.5px; }
.doc-meta { font-size: 11px; color: #4b5563; line-height: 2; margin-top: 5px; }
.doc-meta strong { color: #111827; }

/* ── Partijen ── */
.parties { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; margin-bottom: 28px; }
.party { background: #f9fafb; border: 1px solid #e5e7eb; border-radius: 8px; padding: 16px 18px; }
.party-lbl { font-size: 10px; font-weight: 700; text-transform: uppercase; letter-spacing: .1em; color: #9ca3af; margin-bottom: 6px; }
.party-name { font-size: 13px; font-weight: 700; color: #111827; margin-bottom: 2px; }
.party-detail { font-size: 11.5px; color: #4b5563; line-height: 1.75; }

/* ── Sectie ── */
.section { margin-bottom: 24px; }
.section-title { font-size: 10px; font-weight: 700; text-transform: uppercase; letter-spacing: .09em; color: #6b7280; border-bottom: 1px solid #e5e7eb; padding-bottom: 5px; margin-bottom: 10px; }
.section p { font-size: 12.5px; color: #374151; line-height: 1.75; }
.section ul { padding-left: 18px; }
.section ul li { font-size: 12.5px; color: #374151; line-height: 1.8; }

/* ── Prijstabel ── */
.price-table { width: 100%; border-collapse: collapse; margin-bottom: 0; }
.price-table td { padding: 8px 10px; font-size: 12.5px; border-bottom: 1px solid #f3f4f6; }
.price-table td:last-child { text-align: right; font-variant-numeric: tabular-nums; }
.price-table .muted td { font-size: 12px; color: #9ca3af; }
.price-table .grand td { font-size: 15px; font-weight: 700; color: #111827; border-top: 2px solid #111827; border-bottom: none; padding-top: 10px; }

/* ── Info-kaartjes ── */
.info-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; margin-bottom: 24px; }
.info-card { background: #f9fafb; border: 1px solid #e5e7eb; border-radius: 8px; padding: 14px 16px; }
.info-card .k { font-size: 10px; font-weight: 700; text-transform: uppercase; letter-spacing: .08em; color: #9ca3af; margin-bottom: 3px; }
.info-card .v { font-size: 13px; font-weight: 600; color: #111827; }
.info-card .s { font-size: 11px; color: #6b7280; margin-top: 2px; }

/* ── Akkoordblok ── */
.akkoord { border: 1px solid #e5e7eb; border-radius: 8px; padding: 24px; margin-top: 8px; }
.akkoord-title { font-size: 13px; font-weight: 700; color: #111827; margin-bottom: 8px; }
.akkoord-text { font-size: 12px; color: #6b7280; line-height: 1.7; margin-bottom: 28px; }
.sig-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 32px; }
.sig-lbl { font-size: 11px; color: #9ca3af; margin-bottom: 4px; }
.sig-line { border-bottom: 1px solid #9ca3af; height: 40px; margin-bottom: 6px; }
.sig-name { font-size: 12px; color: #4b5563; }

/* ── Footer ── */
.footer { margin-top: 36px; padding-top: 12px; border-top: 1px solid #e5e7eb; font-size: 10px; color: #9ca3af; display: flex; justify-content: space-between; gap: 16px; line-height: 1.8; }
.footer-r { text-align: right; }
</style>
</head>
<body>

<!-- HEADER -->
<div class="header">
  <div>
    <div class="brand">${fromName}</div>
    <div class="brand-sub">${fromWeb}${fromWeb && fromEmail ? ' · ' : ''}${fromEmail}${fromPhone ? ' · ' + fromPhone : ''}</div>
  </div>
  <div class="doc-block">
    <h1>OFFERTE</h1>
    <div class="doc-meta">
      <strong>Offertenummer:</strong> ${offerteNr}<br/>
      <strong>Datum:</strong> ${dateFmt(vandaag)}<br/>
      <strong>Geldig tot:</strong> ${dateFmt(geldigTot)}
    </div>
  </div>
</div>

<!-- PARTIJEN -->
<div class="parties">
  <div class="party">
    <div class="party-lbl">Aanbieder</div>
    <div class="party-name">${fromName}</div>
    <div class="party-detail">
      ${fromAddr ? fromAddr + '<br/>' : ''}
      ${fromEmail ? fromEmail + '<br/>' : ''}
      ${fromWeb ? fromWeb + '<br/>' : ''}
      ${fromKvk ? 'KVK: ' + fromKvk + '<br/>' : ''}
      ${fromVat ? 'BTW: ' + fromVat : ''}
    </div>
  </div>
  <div class="party">
    <div class="party-lbl">Opdrachtgever</div>
    <div class="party-name">${esc(d.recipientCompany ?? d.recipientName ?? '')}</div>
    <div class="party-detail">
      ${d.recipientCompany && d.recipientName ? esc(d.recipientName) + '<br/>' : ''}
      ${d.recipientAddress ? br(d.recipientAddress) + '<br/>' : ''}
      ${esc(d.recipientEmail ?? '')}
    </div>
  </div>
</div>

<!-- ONDERWERP -->
<div class="section">
  <div class="section-title">Onderwerp</div>
  <p><strong>${esc(d.title ?? '')}</strong></p>
</div>

<!-- OMSCHRIJVING -->
<div class="section">
  <div class="section-title">Omschrijving werkzaamheden</div>
  <p>${br(d.summary ?? '')}</p>
</div>

${scopeItems ? `<!-- SCOPE -->
<div class="section">
  <div class="section-title">Scope</div>
  <ul>${scopeItems}</ul>
</div>` : ''}

${d.deliveryTime ? `<!-- PLANNING -->
<div class="section">
  <div class="section-title">Planning &amp; doorlooptijd</div>
  <p>${esc(d.deliveryTime)}</p>
</div>` : ''}

${d.notes ? `<!-- OPMERKINGEN -->
<div class="section">
  <div class="section-title">Opmerkingen</div>
  <p>${br(d.notes)}</p>
</div>` : ''}

${exclBtw != null ? `<!-- PRIJS -->
<div class="section">
  <div class="section-title">Prijsopgave</div>
  <table class="price-table">
    <tr>
      <td>${esc(d.priceLabel ?? 'Projectprijs')}</td>
      <td>${euro(exclBtw)}</td>
    </tr>
    <tr class="muted">
      <td>BTW ${vatPct}%</td>
      <td>${euro(btwBedrag)}</td>
    </tr>
    <tr class="grand">
      <td>Totaal incl. BTW</td>
      <td>${euro(inclBtw)}</td>
    </tr>
  </table>
</div>

<!-- BETAALAFSPRAKEN -->
<div class="info-grid">
  <div class="info-card">
    <div class="k">Aanbetaling</div>
    <div class="v">${euro(inclBtw * 0.5)} (50%)</div>
    <div class="s">Te voldoen bij akkoord</div>
  </div>
  <div class="info-card">
    <div class="k">Restbetaling</div>
    <div class="v">${euro(inclBtw * 0.5)} (50%)</div>
    <div class="s">Te voldoen bij oplevering</div>
  </div>
  ${d.from?.iban ? `<div class="info-card">
    <div class="k">IBAN</div>
    <div class="v">${esc(d.from.iban)}</div>
    <div class="s">${esc(d.from?.bankName ?? '')}</div>
  </div>` : ''}
  <div class="info-card">
    <div class="k">Geldig tot</div>
    <div class="v">${dateFmt(geldigTot)}</div>
    <div class="s">30 dagen na offertedatum</div>
  </div>
</div>` : ''}

<!-- AKKOORD -->
<div class="akkoord">
  <div class="akkoord-title">Akkoord &amp; ondertekening</div>
  <div class="akkoord-text">
    Door ondertekening gaat u akkoord met de bovenstaande offerte en de bijbehorende voorwaarden.
    ${d.termsUrl ? `Onze algemene voorwaarden zijn beschikbaar op <strong>${esc(d.termsUrl)}</strong>.` : ''}
  </div>
  <div class="sig-grid">
    <div>
      <div class="sig-lbl">Namens aanbieder — ${fromName}</div>
      <div class="sig-line"></div>
      <div class="sig-name">Naam &amp; handtekening</div>
    </div>
    <div>
      <div class="sig-lbl">Namens opdrachtgever — ${esc(d.recipientCompany ?? d.recipientName ?? '')}</div>
      <div class="sig-line"></div>
      <div class="sig-name">Naam &amp; handtekening &nbsp;&nbsp;&nbsp;&nbsp; Datum</div>
    </div>
  </div>
</div>

<!-- FOOTER -->
<div class="footer">
  <div>
    ${fromName}<br/>
    ${fromAddr ? fromAddr + '<br/>' : ''}
    ${fromEmail}
  </div>
  <div class="footer-r">
    ${fromKvk ? 'KVK: ' + fromKvk + '<br/>' : ''}
    ${fromVat ? 'BTW: ' + fromVat + '<br/>' : ''}
    Offerte ${offerteNr}
  </div>
</div>

</body>
</html>`;

return [{ json: { ...d, html } }];
